 1	import React, { FC, PropsWithChildren } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { Button, ButtonVariant } from '@patternfly/react-core';
 5	import AccessDenied from '@utils/components/AccessDenied/AccessDenied';
 6	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 7	
 8	import ListSkeleton from './ListSkeleton';
 9	
10	type StatusBoxProps = PropsWithChildren<{
11	  loaded: boolean;
12	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
13	  error: any;
14	}>;
15	
16	const StatusBox: FC<StatusBoxProps> = ({ loaded, error, children }) => {
17	  const { t } = useNMStateTranslation();
18	
19	  if (error && error?.response?.status === 403) return <AccessDenied message={error.message} />;
20	
21	  if (error)
22	    return (
23	      <div className="cos-status-box loading-box loading-box__errored">
24	        <div className="pf-u-text-align-center cos-error-title">{error?.message}</div>
25	        <div className="pf-u-text-align-center">
26	          <Trans t={t} ns="plugin__nmstate-console-plugin">
27	            Please{' '}
28	            <Button isInline variant={ButtonVariant.link} onClick={() => location.reload()}>
29	              try again
30	            </Button>
31	            .
32	          </Trans>
33	        </div>
34	      </div>
35	    );
36	
37	  if (!loaded) {
38	    return <ListSkeleton />;
39	  }
40	
41	  return <>{children}</>;
42	};
43	
44	export default StatusBox;

